    static let allowedInsecureHosts: Set<String> = []
    
    /// The secure cloud API base URL
    static let cloudAPIBaseURL = URL(string: "https://api.example.com")!
    
    /// Local network IP range prefix for IoT devices
    static let localNetworkPrefix = "192.168."
    
    /// Check if a host is a local network address
    static func isLocalNetworkHost(_ host: String) -> Bool {
