// MARK: - SSL Pinning Delegate

final class SecureSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    static let shared = SecureSessionDelegate()
    
    private override init() {
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    func urlSession(
        _ session: URLSession,
        task: URLSessionTask,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        handleChallenge(challenge, completionHandler: completionHandler)
    }
    
    private func handleChallenge(
        _ challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // For local network devices, we still perform default SSL validation
        // but we don't do certificate pinning (they may use self-signed certs handled via Info.plist)
        if NetworkConfiguration.isLocalNetworkHost(host) {
            // Perform default handling - the system will validate the certificate
            // For local devices using HTTPS with self-signed certs, they should be
            // added to a trust store or use proper certificates
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // For cloud API, enforce certificate pinning
        if let pinnedHashes = CertificatePinning.pinnedCertificateHashes[host] {
            if validateCertificatePin(serverTrust: serverTrust, pinnedHashes: pinnedHashes) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                // Certificate pinning failed - reject the connection
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
            return
        }
        
        // For any other host, use default handling (system certificate validation)
        completionHandler(.performDefaultHandling, nil)
    }
    
    private func validateCertificatePin(serverTrust: SecTrust, pinnedHashes: [String]) -> Bool {
        // Evaluate the trust
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            return false
        }
        
        // Check certificate chain
        guard let certificateChain = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate],
              !certificateChain.isEmpty else {
            return false
        }
        
        // Validate at least one certificate in the chain matches our pins
        for certificate in certificateChain {
            let certData = SecCertificateCopyData(certificate) as Data
            let hash = certData.sha256Base64()
            if pinnedHashes.contains(hash) {
                return true
            }
        }
        
        return false
    }
}

// MARK: - Data Extension for Hashing

import CryptoKit

extension Data {
    func sha256Base64() -> String {
        let hash = SHA256.hash(data: self)
        return Data(hash).base64EncodedString()
    }
}

// MARK: - HTTP Client Error Types

enum HTTPClientError: Error, LocalizedError {
    case invalidURL
    case insecureConnectionBlocked(host: String)
    case noData
    case httpError(statusCode: Int, data: Data?)
    case networkError(Error)
    case decodingError(Error)
    case certificatePinningFailed
    case invalidLocalAddress
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .insecureConnectionBlocked(let host):
            return "Insecure HTTP connection to '\(host)' is not allowed. Use HTTPS or configure the host as a trusted local device."
        case .noData:
            return "No data received"
        case .httpError(let code, _):
            return "HTTP error: \(code)"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .certificatePinningFailed:
            return "Certificate pinning validation failed"
        case .invalidLocalAddress:
            return "The local network address is not valid"
        }
    }
}

