// MARK: - IoT Device Discovery

struct IoTDevice {
    let name: String
    let host: String
    let port: Int
    let usesHTTPS: Bool
    
    var baseURL: URL? {
        let scheme = usesHTTPS ? "https" : "http"
        return URL(string: "\(scheme)://\(host):\(port)")
    }
}

