// MARK: - Cloud API Service

final class CloudAPIService {
    
    private let client: HTTPClient
    private let baseURL: URL
    private var authToken: String?
    
    init(client: HTTPClient = .shared, baseURL: URL = NetworkConfiguration.cloudAPIBaseURL) {
        self.client = client
        self.baseURL = baseURL
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private var authHeaders: [String: String]? {
        guard let token = authToken else { return nil }
        return ["Authorization": "Bearer \(token)"]
    }
    
    // Example: Fetch devices from cloud
    func fetchDevices() async throws -> HTTPResponse<[DeviceInfo]> {
        let url = baseURL.appendingPathComponent("/devices")
        return try await client.request(url: url, headers: authHeaders)
    }
    
    // Example: Register a device
    func registerDevice(_ registration: DeviceRegistration) async throws -> HTTPResponse<DeviceInfo> {
        let url = baseURL.appendingPathComponent("/devices")
        return try await client.request(url: url, method: .POST, headers: authHeaders, body: registration)
    }
    
    // Example: Get device status from cloud
    func getDeviceStatus(deviceId: String) async throws -> HTTPResponse<DeviceStatus> {
        let url = baseURL.appendingPathComponent("/devices/\(deviceId)/status")
        return try await client.request(url: url, headers: authHeaders)
    }
}

// MARK: - Local IoT Device Service

final class LocalDeviceService {
    
    private let client: HTTPClient
    
    init(client: HTTPClient = .shared) {
        self.client = client
    }
    
    /// Register and connect to a local IoT device
    func connectToDevice(_ device: IoTDevice) throws {
        try client.registerLocalDevice(device)
    }
    
    func disconnectDevice(_ device: IoTDevice) {
        client.unregisterLocalDevice(host: device.host)
    }
    
    /// Get status from a local IoT device
    func getDeviceStatus(_ device: IoTDevice) async throws -> HTTPResponse<DeviceStatus> {
        guard let baseURL = device.baseURL else {
            throw HTTPClientError.invalidURL
        }
        let url = baseURL.appendingPathComponent("/status")
        return try await client.request(url: url)
    }
    
    /// Send a command to a local IoT device
    func sendCommand(_ command: DeviceCommand, to device: IoTDevice) async throws -> HTTPResponse<CommandResponse> {
        guard let baseURL = device.baseURL else {
            throw HTTPClientError.invalidURL
        }
        let url = baseURL.appendingPathComponent("/command")
        return try await client.request(url: url, method: .POST, body: command)
    }
    
    /// Get sensor data from a local IoT device
    func getSensorData(_ device: IoTDevice) async throws -> HTTPResponse<SensorData> {
        guard let baseURL = device.baseURL else {
            throw HTTPClientError.invalidURL
        }
        let url = baseURL.appendingPathComponent("/sensors")
        return try await client.request(url: url)
    }
    
    /// Update firmware on a local IoT device
    func updateFirmware(_ device: IoTDevice, firmwareData: Data) async throws -> HTTPResponse<FirmwareUpdateResponse> {
        guard let baseURL = device.baseURL else {
            throw HTTPClientError.invalidURL
        }
        let url = baseURL.appendingPathComponent("/firmware/update")
        return try await client.request(
            url: url,
            method: .POST,
            headers: ["Content-Type": "application/octet-stream"],
            body: firmwareData
        )
    }
}

// MARK: - Model Types

struct DeviceInfo: Codable {
    let id: String
    let name: String
    let type: String
    let firmwareVersion: String
    let isOnline: Bool
}

struct DeviceRegistration: Codable {
    let name: String
    let type: String
    let macAddress: String
}

struct DeviceStatus: Codable {
    let isOnline: Bool
    let uptime: TimeInterval
    let firmwareVersion: String
    let batteryLevel: Double?
    let signalStrength: Int?
}

struct DeviceCommand: Codable {
    let action: String
    let parameters: [String: String]?
}

struct CommandResponse: Codable {
    let success: Bool
    let message: String?
    let resultData: [String: String]?
}

struct SensorData: Codable {
    let temperature: Double?
    let humidity: Double?
    let pressure: Double?
    let lightLevel: Double?
    let motion: Bool?
    let timestamp: Date
}

struct FirmwareUpdateResponse: Codable {
    let success: Bool
    let message: String
    let newVersion: String?
}

// MARK: - Usage Example

@MainActor
final class DeviceManager {
    
    private let cloudService = CloudAPIService()
    private let localService = LocalDeviceService()
    
    func demonstrateUsage() async {
        // 1. Set up cloud API authentication
        cloudService.setAuthToken("your-jwt-token-here")
        
        // 2. Register a local IoT device (legacy HTTP device)
        let legacyDevice = IoTDevice(
            name: "Living Room Thermostat",
            host: "192.168.1.100",
            port: 80,
            usesHTTPS: false
        )
        
        // 3. Register a local IoT device (modern HTTPS device)
        let modernDevice = IoTDevice(
            name: "Smart Lock",
            host: "192.168.1.101",
            port: 443,
            usesHTTPS: true
        )
        
        do {
            // Register local devices as trusted
            try localService.connectToDevice(legacyDevice)
            try localService.connectToDevice(modernDevice)
            
            // Fetch devices from cloud API (always HTTPS)
            let cloudDevices = try await cloudService.fetchDevices()
            print("Cloud devices: \(cloudDevices.data)")
            
            // Get status from local legacy device (HTTP - allowed because registered)
            let legacyStatus = try await localService.getDeviceStatus(legacyDevice)
            print("Legacy device status: \(legacyStatus.data)")
            
            // Get status from local modern device (HTTPS)
            let modernStatus = try await localService.getDeviceStatus(modernDevice)
            print("Modern device status: \(modernStatus.data)")
            
            // Send command to local device
            let command = DeviceCommand(action: "setTemperature", parameters: ["value": "72"])
            let response = try await localService.sendCommand(command, to: legacyDevice)
            print("Command response: \(response.data)")
            
            // This would FAIL - trying to use HTTP with a non-local address
            // let maliciousURL = URL(string: "http://evil-server.com/steal-data")!
            // try await HTTPClient.shared.requestData(url: maliciousURL) // Throws insecureConnectionBlocked
            
            // This would also FAIL - unregistered local device
            // let unregisteredDevice = IoTDevice(name: "Unknown", host: "192.168.1.200", port: 80, usesHTTPS: false)
            // try await localService.getDeviceStatus(unregisteredDevice) // Throws insecureConnectionBlocked
            
        } catch {
            print("Error: \(error.localizedDescription)")
        }
    }
}